import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Button, StatusBadge, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { gtService } from '../../../services/gt/gtService';
import type { CostSheetDto, CostElementDto } from '../../../services/gt/models';
import { formatVnd } from '../../../utils/formatters';
import erp from '../../../styles/erpPage.module.css';

const GiaThanhDetailPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const dispatch = useAppDispatch();
  const [sheet, setSheet] = useState<CostSheetDto | null>(null);
  const [elements, setElements] = useState<CostElementDto[]>([]);
  const [loading, setLoading] = useState(false);

  React.useEffect(() => {
    if (!id) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      Promise.all([gtService.getCostSheet(id), gtService.getCostElements(id)])
        .then(([s, els]) => { if (!cancelled) { setSheet(s); setElements(els); } })
        .catch(err => { if (!cancelled) dispatch(addToast({ message: err?.message ?? 'Lỗi tải chi tiết', type: 'error' })); })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [id]);

  if (loading || !sheet) return <div className={erp.loading}>Đang tải...</div>;

  return (
    <div className={erp.page}>
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}>
          <button type="button" className={erp.codeLink} onClick={() => navigate('/gt/gia-thanh')}>← Quay lại</button>
          <h1 className={erp.title}>Giá thành — {sheet.code} <StatusBadge status={sheet.status} /></h1>
        </div>
      </div>
      <div className={erp.summaryBar}>
        <div className={erp.summaryItem}><label className={erp.label}>Sản phẩm</label><strong>{sheet.productName ?? sheet.productCode}</strong></div>
        <div className={erp.summaryItem}><label className={erp.label}>Kỳ</label><strong>{sheet.month}/{sheet.year}</strong></div>
        <div className={erp.summaryItem}><label className={erp.label}>SL thực tế</label><strong>{sheet.actualQty}</strong></div>
        <div className={erp.summaryItem}><label className={erp.label}>Tổng giá thành</label><strong>{formatVnd(sheet.totalCost)}</strong></div>
        <div className={erp.summaryItem}><label className={erp.label}>Giá thành ĐV</label><strong>{formatVnd(sheet.unitCost)}</strong></div>
      </div>
      <div className={erp.tableCard}>
        <div className={erp.tableWrapper}>
          <table className={erp.table}>
            <thead><tr><th>Loại YT</th><th>Diễn giải</th><th>TK</th><th className={erp.colRight}>Số tiền</th></tr></thead>
            <tbody>{elements.map((el, i) => (
              <tr key={el.id ?? i}>
                <td>{el.elementType}</td>
                <td>{el.description}</td>
                <td><code>{el.accountCode}</code></td>
                <td className={erp.colRight}>{formatVnd(el.amount)}</td>
              </tr>
            ))}</tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default GiaThanhDetailPage;
